function factorial(n) {
  if (n === 0) {
    return 1;
  } else {
    return n * factorial(n - 1);
  }
}
console.log(factorial(5));  // 120

function outer() {
  var counter = 0;
  return function() {
    return ++counter;
  };
}
var myFunc = outer();
console.log(myFunc());  // 1
console.log(myFunc());  // 2

function greeting(name) {
  console.log('Hello, ' + name);
}
function processUserInput(callback) {
  var name = prompt('Please enter your name.');
  callback(name);
}
processUserInput(greeting);  // 'Hello, [user_input]'

(function() {
  var message = 'Hello, World!';
  console.log(message);  // 'Hello, World!'
})();

function outerFunction(outerVariable) {
  return function innerFunction(innerVariable) {
    console.log('outer: ' + outerVariable + ', inner: ' + innerVariable);
  }
}
const newFunction = outerFunction('outside');
newFunction('inside');  // 'outer: outside, inner: inside'

function multiply(a, b) {
  return a * b;
}
function curriedMultiply(a) {
  return function(b) {
    return multiply(a, b);
  }
}
const multiplyByTwo = curriedMultiply(2);
multiplyByTwo(3);  // 6

function asyncGreeting() {
  setTimeout(() => {
    console.log('Hello, World!');
  }, 1000);
}
asyncGreeting();  // 1秒後に 'Hello, World!' を出力

function asyncGreeting() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      resolve('Hello, World!');
    }, 1000);
  });
}
asyncGreeting().then(message => console.log(message));  // 1秒後に 'Hello, World!' を出力

function delayGreeting() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      resolve('Hello, World!');
    }, 1000);
  });
}
async function asyncGreeting() {
  let message = await delayGreeting();
  console.log(message);  // 1秒後に 'Hello, World!' を出力
}
asyncGreeting();

function riskyBusiness() {
  try {
    // 何かリスキーな操作
    throw new Error('Something went wrong!');
  } catch (error) {
    console.log(error.message);  // 'Something went wrong!' を出力
  }
}
riskyBusiness();

function higherOrderFunction(callback) {
  // 引数として受け取った関数を実行
  let result = callback();
  console.log(result);
}
function greeting() {
  return 'Hello, World!';
}
higherOrderFunction(greeting);  // 'Hello, World!' を出力

(function() {
  let privateVariable = 'Hello, World!';
  console.log(privateVariable);  // 'Hello, World!' を出力
})();

function delayedExecution(callback) {
  // setTimeoutを使用して、引数の関数を1秒後に実行
  setTimeout(callback, 1000);
}
function sayHello() {
  console.log('Hello, World!');
}
delayedExecution(sayHello);  // 1秒後に 'Hello, World!' を出力

function outerFunction() {
  let message = 'Hello, World!';
  return function innerFunction() {
    console.log(message);  // 'Hello, World!' を出力
  };
}
let closure = outerFunction();
closure();  // 'Hello, World!' を出力
